// ==================== WS-Security Timestamp Handler ====================

class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSS_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final long MAX_TIMESTAMP_AGE_MS = 300000; // 5 minutes
    private static final SimpleDateFormat ISO_FORMAT = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");

    static {
        ISO_FORMAT.setTimeZone(TimeZone.getTimeZone("UTC"));
    }

    private final ReplayDetectionCache replayCache = ReplayDetectionCache.getInstance();

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSS_NS, "Security"));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (outbound != null && outbound) {
            return handleOutboundMessage(context);
        } else {
            return handleInboundMessage(context);
        }
    }

    private boolean handleOutboundMessage(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();
            if (header == null) {
                header = envelope.addHeader();
            }

            // Add WS-Security header with timestamp
            SOAPElement securityElement = header.addChildElement("Security", "wsse", WSS_NS);
            securityElement.addNamespaceDeclaration("wsu", WSU_NS);

            SOAPElement timestampElement = securityElement.addChildElement("Timestamp", "wsu", WSU_NS);

            String messageId = UUID.randomUUID().toString();
            timestampElement.addAttribute(new QName(WSU_NS, "Id", "wsu"), "TS-" + messageId);

            Date now = new Date();
            Date expires = new Date(now.getTime() + MAX_TIMESTAMP_AGE_MS);

            SOAPElement createdElement = timestampElement.addChildElement("Created", "wsu", WSU_NS);
            createdElement.addTextNode(formatDate(now));

            SOAPElement expiresElement = timestampElement.addChildElement("Expires", "wsu", WSU_NS);
            expiresElement.addTextNode(formatDate(expires));

            // Add MessageID for replay detection
            SOAPElement messageIdElement = securityElement.addChildElement("MessageID", "wsse", WSS_NS);
            messageIdElement.addTextNode(messageId);

            message.saveChanges();

            System.out.println("[WS-Security] Outbound timestamp added. MessageID: " + messageId);
            return true;
        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error adding outbound timestamp: " + e.getMessage());
            throw new WsSecurityException("Failed to add security timestamp", "wsse:InvalidSecurity");
        }
    }

    private boolean handleInboundMessage(SOAPMessageContext context) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPEnvelope envelope = message.getSOAPPart().getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                throw new WsSecurityException("Missing SOAP Security header", "wsse:InvalidSecurity");
            }

            TimestampToken timestampToken = extractTimestampToken(header);

            if (timestampToken == null) {
                throw new WsSecurityException("Missing WS-Security Timestamp", "wsse:InvalidSecurity");
            }

            System.out.println("[WS-Security] Extracted timestamp: " + timestampToken);

            // Validate timestamp is not expired
            if (timestampToken.isExpired()) {
                throw new WsSecurityException(
                    "Security timestamp has expired. Expires: " + timestampToken.getExpires(),
                    "wsse:MessageExpired"
                );
            }

            // Validate timestamp is not too old (created time check)
            Date now = new Date();
            long ageMs = now.getTime() - timestampToken.getCreated().getTime();
            if (ageMs > MAX_TIMESTAMP_AGE_MS) {
                throw new WsSecurityException(
                    "Timestamp is too old. Age: " + ageMs + "ms, Max: " + MAX_TIMESTAMP_AGE_MS + "ms",
                    "wsse:MessageExpired"
                );
            }

            // Validate timestamp is not from the future
            if (timestampToken.getCreated().after(new Date(now.getTime() + 60000))) {
                throw new WsSecurityException(
                    "Timestamp created time is in the future",
                    "wsse:InvalidSecurity"
                );
            }

            // Check for replay attack
            String messageId = timestampToken.getMessageId();
            if (messageId != null && !messageId.isEmpty()) {
                if (replayCache.isReplay(messageId)) {
                    throw new WsSecurityException(
                        "Replay attack detected. MessageID: " + messageId,
                        "wsse:ReplayAttack"
                    );
                }
                replayCache.recordMessage(messageId, timestampToken);
            }

            System.out.println("[WS-Security] Inbound message validated successfully. MessageID: " + messageId);
            return true;

        } catch (WsSecurityException e) {
            System.err.println("[WS-Security] Security validation failed: " + e.getMessage());
            generateSOAPFault(context, e);
            return false;
        } catch (SOAPException e) {
            System.err.println("[WS-Security] Error processing security header: " + e.getMessage());
            generateSOAPFault(context, new WsSecurityException(
                "Error processing security header: " + e.getMessage(), "wsse:InvalidSecurity"));
            return false;
        }
    }

    private TimestampToken extractTimestampToken(SOAPHeader header) throws SOAPException {
        String createdStr = null;
        String expiresStr = null;
        String messageId = null;

        Iterator<?> securityHeaders = header.getChildElements(new QName(WSS_NS, "Security"));

        if (!securityHeaders.hasNext()) {
            // Try alternative namespace
            securityHeaders = header.getChildElements();
        }

        while (securityHeaders.hasNext()) {
            Object obj = securityHeaders.next();
            if (!(obj instanceof SOAPElement)) continue;

            SOAPElement securityElement = (SOAPElement) obj;
            String localName = securityElement.getLocalName();

            if ("Security".equals(localName)) {
                // Extract Timestamp
                Iterator<?> timestampElements = securityElement.getChildElements(
                    new QName(WSU_NS, "Timestamp"));

                while (timestampElements.hasNext()) {
                    Object tsObj = timestampElements.next();
                    if (!(tsObj instanceof SOAPElement)) continue;

                    SOAPElement timestampElement = (SOAPElement) tsObj;

                    Iterator<?> createdElements = timestampElement.getChildElements(
                        new QName(WSU_NS, "Created"));
                    if (createdElements.hasNext()) {
                        Object cObj = createdElements.next();
                        if (cObj instanceof SOAPElement) {
                            createdStr = ((SOAPElement) cObj).getTextContent().trim();
                        }
                    }

                    Iterator<?> expiresElements = timestampElement.getChildElements(
                        new QName(WSU_NS, "Expires"));
                    if (expiresElements.hasNext()) {
                        Object eObj = expiresElements.next();
                        if (eObj instanceof SOAPElement) {
                            expiresStr = ((SOAPElement) eObj).getTextContent().trim();
                        }
                    }
                }

                // Extract MessageID
                Iterator<?> msgIdElements = securityElement.getChildElements(
                    new QName(WSS_NS, "MessageID"));
                if (msgIdElements.hasNext()) {
                    Object mObj = msgIdElements.next();
                    if (mObj instanceof SOAPElement) {
                        messageId = ((SOAPElement) mObj).getTextContent().trim();
                    }
                }
            }
        }

        if (createdStr == null || expiresStr == null) {
            return null;
        }

        Date created = parseDate(createdStr);
        Date expires = parseDate(expiresStr);

        if (created == null || expires == null) {
            throw new WsSecurityException("Invalid timestamp format", "wsse:InvalidSecurity");
        }

        return new TimestampToken(created, expires, messageId);
    }

    private void generateSOAPFault(SOAPMessageContext context, WsSecurityException e) {
        try {
            SOAPMessage message = context.getMessage();
            SOAPBody body = message.getSOAPPart().getEnvelope().getBody();
            body.removeContents();

            SOAPFault fault = body.addFault();
            fault.setFaultCode(e.getFaultCode());
            fault.setFaultString(e.getMessage());
            fault.setFaultActor("PaymentGateway/WSSecurity");

            message.saveChanges();
        } catch (SOAPException se) {
            System.err.println("[WS-Security] Failed to generate SOAP fault: " + se.getMessage());
        }
    }

    private synchronized String formatDate(Date date) {
        return ISO_FORMAT.format(date);
    }

    private synchronized Date parseDate(String dateStr) {
        try {
            return ISO_FORMAT.parse(dateStr);
        } catch (ParseException e) {
            // Try alternative formats
            String[] alternativeFormats = {
                "yyyy-MM-dd'T'HH:mm:ss'Z'",
                "yyyy-MM-dd'T'HH:mm:ssXXX",
                "yyyy-MM-dd'T'HH:mm:ss.SSSXXX"
            };
            for (String format : alternativeFormats) {
                try {
                    SimpleDateFormat sdf = new SimpleDateFormat(format);
                    sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
                    return sdf.parse(dateStr);
                } catch (ParseException ignored) {}
            }
            System.err.println("[WS-Security] Failed to parse date: " + dateStr);
            return null;
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        System.err.println("[WS-Security] Handling SOAP fault in security handler");
        return true;
    }

    @Override
    public void close(MessageContext context) {
        // Cleanup if needed
    }
}

